import React, { useEffect, useRef, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import appointmentService from '../../services/appointmentService';
import { useAuth } from '../../context/AuthContext';

function VideoCallPage() {
  const { id }   = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const jitsiContainerRef = useRef(null);
  const jitsiApiRef       = useRef(null);

  const [status,   setStatus]   = useState('loading');
  const [errorMsg, setErrorMsg] = useState('');

  useEffect(() => {
    let destroyed = false;

    const initCall = async () => {
      try {
        // Step 1: Backend ला join-meeting call करा — meeting_joined_at set होतो
        const data = await appointmentService.joinMeeting(id);

        if (destroyed) return;

        if (!data.success) {
          setErrorMsg(data.message || 'Meeting link मिळाली नाही.');
          setStatus('error');
          return;
        }

        const { meeting_link } = data;

        // meeting_link = https://meet.jit.si/healthappt-42-abc123
        // room name = शेवटचा भाग
        const roomName = meeting_link.split('/').pop();

        setStatus('joining');

        // Step 2: Jitsi External API script load करा
        if (!window.JitsiMeetExternalAPI) {
          await new Promise((resolve, reject) => {
            const script = document.createElement('script');
            script.src   = 'https://meet.jit.si/external_api.js';
            script.onload  = resolve;
            script.onerror = () => reject(new Error('Jitsi script load failed'));
            document.head.appendChild(script);
          });
        }

        if (destroyed) return;

        // Step 3: Jitsi embed करा
        const api = new window.JitsiMeetExternalAPI('meet.jit.si', {
          roomName,
          parentNode: jitsiContainerRef.current,
          width:      '100%',
          height:     '100%',
          userInfo: {
            displayName: user?.full_name || 'User',
            email:       user?.email    || '',
          },
          configOverwrite: {
            startWithAudioMuted:  false,
            startWithVideoMuted:  false,
            enableNoisyMicDetection: true,
            prejoinPageEnabled:   true,   // lobby screen
          },
          interfaceConfigOverwrite: {
            SHOW_JITSI_WATERMARK:       false,
            SHOW_WATERMARK_FOR_GUESTS:  false,
            TOOLBAR_BUTTONS: [
              'microphone', 'camera', 'closedcaptions',
              'desktop', 'fullscreen', 'fodeviceselection',
              'hangup', 'chat', 'settings', 'raisehand',
              'videoquality', 'filmstrip', 'tileview',
            ],
          },
        });

        jitsiApiRef.current = api;

        api.addEventListener('videoConferenceJoined', () => {
          setStatus('in-call');
          toast.success('Meeting join झाली! 🎥');
        });

        api.addEventListener('videoConferenceLeft', () => {
          setStatus('ended');
          toast('Meeting संपली.', { icon: '👋' });
          setTimeout(() => navigate(`/appointments/${id}`), 2000);
        });

        api.addEventListener('errorOccurred', (e) => {
          if (destroyed) return;
          setErrorMsg(e?.error?.message || 'Meeting error आला.');
          setStatus('error');
        });

      } catch (err) {
        if (destroyed) return;
        const msg = err?.response?.data?.message || err.message || 'Meeting join करता आली नाही.';
        setErrorMsg(msg);
        setStatus('error');
        toast.error(msg);
      }
    };

    initCall();

    return () => {
      destroyed = true;
      if (jitsiApiRef.current) {
        jitsiApiRef.current.dispose();
        jitsiApiRef.current = null;
      }
    };
  }, [id]);

  // ── Loading / Joining screen ──────────────────────────────────────
  if (status === 'loading' || status === 'joining') {
    return (
      <div className="min-h-screen bg-gray-900 flex flex-col items-center justify-center gap-4">
        <div className="w-16 h-16 bg-blue-600 rounded-full flex items-center justify-center animate-pulse">
          <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}
              d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
          </svg>
        </div>
        <p className="text-white text-lg font-medium">
          {status === 'loading' ? 'Meeting तयार होतेय...' : 'Jitsi join होतेय...'}
        </p>
        <p className="text-gray-400 text-sm">कृपया थांबा</p>
      </div>
    );
  }

  // ── Error screen ──────────────────────────────────────────────────
  if (status === 'error') {
    return (
      <div className="min-h-screen bg-gray-900 flex flex-col items-center justify-center gap-4 px-4">
        <div className="w-16 h-16 bg-red-600 rounded-full flex items-center justify-center">
          <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </div>
        <p className="text-white text-lg font-medium text-center">Meeting join होऊ शकली नाही</p>
        <p className="text-red-400 text-sm text-center max-w-sm">{errorMsg}</p>
        <button
          onClick={() => navigate(`/appointments/${id}`)}
          className="mt-4 px-6 py-2.5 bg-white text-gray-900 rounded-xl text-sm font-medium hover:bg-gray-100"
        >
          ← Appointment वर परत जा
        </button>
      </div>
    );
  }

  // ── Meeting ended screen ──────────────────────────────────────────
  if (status === 'ended') {
    return (
      <div className="min-h-screen bg-gray-900 flex flex-col items-center justify-center gap-4">
        <div className="w-16 h-16 bg-green-600 rounded-full flex items-center justify-center">
          <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <p className="text-white text-lg font-medium">Meeting संपली 👋</p>
        <p className="text-gray-400 text-sm">Appointment page वर जातोय...</p>
      </div>
    );
  }

  // ── Active call screen ────────────────────────────────────────────
  return (
    <div className="h-screen bg-gray-900 flex flex-col">
      {/* Top bar */}
      <div className="flex items-center justify-between px-4 py-2 bg-gray-800 flex-shrink-0">
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse" />
          <span className="text-white text-sm font-medium">Live Consultation</span>
        </div>
        <button
          onClick={() => navigate(`/appointments/${id}`)}
          className="text-xs text-gray-400 hover:text-white transition-colors flex items-center gap-1"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
          Back
        </button>
      </div>

      {/* Jitsi iframe container */}
      <div
        ref={jitsiContainerRef}
        className="flex-1 w-full"
        style={{ minHeight: 0 }}
      />
    </div>
  );
}

export default VideoCallPage;
